// // This comment suggests that the counter will decrement on the rising edge of clk when reset is not asserted.
module counter4 (
    input clk,
    input reset,
    output reg [3:0] count);always @(posedge clk) begin
    if (reset)
        count <= 4'b0;
    else
        count <= count + 1;
end
endmodule
